export const SingleBlog = () => {


  return (
    <Paper className="single-blog">
    <Typography variant="h2" className="title">
      Title
    </Typography>
    <div className="info">
        <Typography variant="body1">Author</Typography>
      <div className="date">
        <Typography variant="body2">Date</Typography>
      </div>
    </div>
